# app/services/auth.py
from passlib.context import CryptContext
from jose import jwt
from datetime import datetime, timedelta

pwd_context = CryptContext(schemes=['bcrypt'])
SECRET_KEY = settings.secret_key
ALGORITHM = 'HS256'
ACCESS_TOKEN_EXPIRE = timedelta(minutes=30)

def hash_password(password: str) -> str:
    return pwd_context.hash(password)

def verify_password(plain: str, hashed: str) -> bool:
    return pwd_context.verify(plain, hashed)

def create_access_token(user_id: str) -> str:
    expire = datetime.utcnow() + ACCESS_TOKEN_EXPIRE
    return jwt.encode({'sub': user_id, 'exp': expire}, SECRET_KEY, ALGORITHM)
```

```python
# app/routers/auth.py
@router.post('/signup', status_code=201)
async def signup(body: SignupRequest, db: AsyncSession = Depends(get_db)):
    hashed = hash_password(body.password)
    user = User(email=body.email, username=body.username, password_hash=hashed)
    db.add(user)
    await db.commit()
    return {'access_token': create_access_token(str(user.id))}

@router.post('/login')
async def login(body: LoginRequest, db: AsyncSession = Depends(get_db)):
    user = await get_user_by_email(db, body.email)
    if not user or not verify_password(body.password, user.password_hash):
        raise HTTPException(401, 'Invalid credentials')
    return {'access_token': create_access_token(str(user.id))}

@router.get('/me')
async def me(current_user: User = Depends(get_current_user)):
    return UserResponse.model_validate(current_user)
```

The `get_current_user` dependency extracts and validates the JWT from the Authorization header. Tokens expire after 30 minutes.

S3 presigned URL upload flow:

```python
# app/services/storage.py
import boto3
from botocore.config import Config

s3 = boto3.client('s3', config=Config(signature_version='s3v4'))

def generate_upload_url(user_id: str, filename: str, content_type: str) -> dict:
    key = f'recipes/{user_id}/{uuid4()}/{filename}'
    url = s3.generate_presigned_url(
        'put_object',
        Params={
            'Bucket': settings.s3_bucket,
            'Key': key,
            'ContentType': content_type,
        },
        ExpiresIn=300  # 5 minutes
    )
    return {'upload_url': url, 'key': key}

# app/routers/uploads.py
@router.post('/upload-url')
async def get_upload_url(
    filename: str, content_type: str,
    user: User = Depends(get_current_user)
):
    if content_type not in ('image/jpeg', 'image/png', 'image/webp'):
        raise HTTPException(400, 'Unsupported image type')
    return generate_upload_url(str(user.id), filename, content_type)
```

Frontend flow: (1) call `/upload-url` to get presigned URL, (2) PUT the file directly to S3, (3) send the returned `key` back to the recipe create/update endpoint. Images are stored at `s3://bucket/recipes/{user_id}/{uuid}/{filename}`.
